import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function scoreContractRisk(chainName, contractAddress) {
  const [events, approvals] = await Promise.all([
    client.BaseService.getLogEventsByAddress(chainName, contractAddress),
    client.SecurityService.getApprovals(chainName, contractAddress),
  ]);
  const eventCount = events.data?.items?.length ?? 0;
  const riskyApprovals = (approvals.data?.items ?? []).filter(a => (a.risk_score ?? 0) > 70);
  const riskLevel = riskyApprovals.length > 5 ? "HIGH" : riskyApprovals.length > 1 ? "MEDIUM" : "LOW";
  return { contractAddress, riskLevel, eventCount, riskyApprovals: riskyApprovals.length };
}
